from openai import OpenAI
from typing import Callable

class Agent:
    """A simple ReAct agent implementation."""

    def __init__(self, system_prompt: str, tools: list[dict]):
        self.client = OpenAI()
        self.system_prompt = system_prompt
        self.tools = tools
        self.tool_registry: dict[str, Callable] = {}
        self.messages = [{"role": "system", "content": system_prompt}]

    def register_tool(self, name: str, func: Callable):
        """Register a tool function."""
        self.tool_registry[name] = func

    def run(self, query: str, max_steps: int = 10) -> str:
        """Run the agent loop."""
        self.messages.append({"role": "user", "content": query})

        for step in range(max_steps):
            response = self.client.chat.completions.create(
                model="gpt-5",
                messages=self.messages,
                tools=self.tools
            )

            msg = response.choices[0].message
            self.messages.append(msg)

            # No tool calls means we're done
            if not msg.tool_calls:
                return msg.content

            # Execute each tool call
            for tool_call in msg.tool_calls:
                func_name = tool_call.function.name
                import json
                args = json.loads(tool_call.function.arguments)

                # Call the registered tool
                result = self.tool_registry[func_name](**args)

                self.messages.append({
                    "role": "tool",
                    "tool_call_id": tool_call.id,
                    "content": str(result)
                })

        return "Max steps reached"

# Usage
agent = Agent(
    system_prompt="You are a helpful research assistant.",
    tools=[{
        "type": "function",
        "function": {
            "name": "search",
            "description": "Search the web",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {"type": "string"}
                },
                "required": ["query"]
            }
        }
    }]
)

agent.register_tool("search", lambda query: f"Results for: {query}")
response = agent.run("What is quantum computing?")
print(response)
